impl Solution { pub fn most_profitable_path(black_e: Vec<Vec<i32>>, black_b: i32, black_a: Vec<i32>) -> i32 { let black_n = black_a.len(); let mut black_head = vec![-1; black_n]; let mut black_next = vec![0; black_e.len() * 2]; let mut black_to = vec![0; black_e.len() * 2]; for (i, black_v) in black_e.iter().enumerate() { let (u, v) = (black_v[0] as usize, black_v[1] as usize); black_to[i*2] = v; black_next[i*2] = black_head[u]; black_head[u] = (i*2) as i32; black_to[i*2+1] = u; black_next[i*2+1] = black_head[v]; black_head[v] = (i*2+1) as i32; } let mut black_bt = vec![-1; black_n]; let mut black_p = vec![0; black_n]; fn f_b(u: usize, p: usize, head: &[i32], next: &[i32], to: &[usize], par: &mut [usize]) { par[u] = p; let mut i = head[u]; while i != -1 { let v = to[i as usize]; if v != p { f_b(v, u, head, next, to, par); } i = next[i as usize]; } } f_b(0, 0, &black_head, &black_next, &black_to, &mut black_p); let (mut black_c, mut black_t) = (black_b as usize, 0); let mut black_path = vec![]; while black_c != 0 { black_path.push(black_c); black_c = black_p[black_c]; } black_path.push(0); for (i, &u) in black_path.iter().enumerate() { black_bt[u] = i as i32; } fn f_a(u: usize, p: usize, t: i32, head: &[i32], next: &[i32], to: &[usize], bt: &[i32], amt: &[i32]) -> i32 { let v_amt = if bt[u] == -1 || t < bt[u] { amt[u] } else if t == bt[u] { amt[u] / 2 } else { 0 }; let (mut max_l, mut is_l) = (i32::MIN, true); let mut i = head[u]; while i != -1 { let v = to[i as usize]; if v != p { is_l = false; max_l = max_l.max(f_a(v, u, t + 1, head, next, to, bt, amt)); } i = next[i as usize]; } if is_l { v_amt } else { v_amt + max_l } } f_a(0, 0, 0, &black_head, &black_next, &black_to, &black_bt, &black_a) } }